// src/pages/FarmEditPage.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import speciesOptions from '../data/speciesData';

function FarmEditPage() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const [farmData, setFarmData] = useState({
    // ... các trường state của bạn giữ nguyên ...
    tenLamSan: '',
    tenKhoaHoc: '',
  });

  const [loading, setLoading] = useState(true);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  
  // THÊM MỚI: State để điều khiển giao diện
  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  useEffect(() => {
    const fetchFarmData = async () => {
      setLoading(true);
      try {
        const response = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const data = response.data;
        
        // Định dạng lại ngày tháng
        if (data.ngayThanhLap) data.ngayThanhLap = new Date(data.ngayThanhLap).toISOString().split('T')[0];
        // ... các trường ngày khác ...

        setFarmData(data);
        
        // CẬP NHẬT: Logic kiểm tra và hiển thị cho Tên lâm sản
        const existingSpecies = data.tenLamSan;
        const isInOptions = speciesOptions.some(s => s.tenLamSan === existingSpecies);

        if (existingSpecies && !isInOptions) {
          // Nếu loài đã có không nằm trong danh sách gợi ý -> tự động bật chế độ nhập tay
          setSelectedSpecies('manual');
          setIsManualEntry(true);
        } else {
          // Nếu có trong danh sách hoặc chưa có -> dùng dropdown
          setSelectedSpecies(existingSpecies || '');
          setIsManualEntry(false);
        }

      } catch (error) {
        // ... xử lý lỗi ...
      } finally {
        setLoading(false);
      }
    };
    if (farmId) fetchFarmData();
  }, [farmId, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFarmData(prev => ({ ...prev, [name]: value }));
  };

  // THÊM MỚI: Hàm xử lý riêng cho dropdown loài
  const handleSpeciesChange = (e) => {
    const value = e.target.value;
    setSelectedSpecies(value);

    if (value === 'manual' || value === 'Nhập thủ công') {
      setIsManualEntry(true);
      setFarmData(prev => ({ ...prev, tenLamSan: '', tenKhoaHoc: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesOptions.find(s => s.tenLamSan === value);
      setFarmData(prev => ({
        ...prev,
        tenLamSan: matched ? matched.tenLamSan : '',
        tenKhoaHoc: matched ? matched.tenKhoaHoc : '',
      }));
    }
  };

  const handleSubmit = async (e) => {
    // ... logic handleSubmit của bạn giữ nguyên ...
  };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;

  return (
    <div className="form-container">
      <h1>Chỉnh sửa thông tin cơ sở</h1>
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      <form onSubmit={handleSubmit}>
        {/* ... các section Thông tin cơ sở, Người đại diện giữ nguyên ... */}

        {/* CẬP NHẬT: Nâng cấp khu vực Thông tin Loài */}
        {(farmData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' || farmData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ') && (
            <section className="khai-bao-section">
                <h3>Thông tin Loài</h3>
                <div className="form-grid">
                    <div className="form-group">
                        <label htmlFor="speciesSelection">Tên lâm sản:</label>
                        <select 
                            id="speciesSelection"
                            value={selectedSpecies}
                            onChange={handleSpeciesChange}
                        >
                            <option value="">-- Chọn hoặc nhập thủ công --</option>
                            {speciesOptions.map((option, index) => (
                                <option key={index} value={option.tenLamSan}>
                                    {option.tenLamSan}
                                </option>
                            ))}
                        </select>
                    </div>
                    
                    {!isManualEntry && selectedSpecies && selectedSpecies !== 'manual' && (
                        <div className="form-group">
                            <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
                            <input type="text" id="tenKhoaHoc" name="tenKhoaHoc" value={farmData.tenKhoaHoc} readOnly disabled />
                        </div>
                    )}

                    {isManualEntry && (
                        <>
                            <div className="form-group">
                                <label htmlFor="tenLamSan">Tên lâm sản (nhập tay):</label>
                                <input 
                                    type="text" 
                                    id="tenLamSan" 
                                    name="tenLamSan" 
                                    value={farmData.tenLamSan} 
                                    onChange={handleChange} 
                                    placeholder="Nhập tên lâm sản" 
                                    required
                                />
                            </div>
                            <div className="form-group">
                                <label htmlFor="tenKhoaHoc">Tên khoa học (nhập tay):</label>
                                <input 
                                    type="text" 
                                    id="tenKhoaHoc" 
                                    name="tenKhoaHoc" 
                                    value={farmData.tenKhoaHoc} 
                                    onChange={handleChange} 
                                    placeholder="Nhập tên khoa học" 
                                />
                            </div>
                        </>
                    )}
                </div>
            </section>
        )}

        {/* ... các section và nút submit/cancel giữ nguyên ... */}
      </form>
    </div>
  );
}

export default FarmEditPage;
